(function(global){'use strict';const SITE_URL = 'https://portfoygayrimenkul.com.tr';const SITE_NAME = 'Portföy Gayrimenkul';const DEFAULT_DESC = "Fethiye ve Muğla'da satılık,kiralık,yatırımlık gayrimenkul.Portföy Gayrimenkul ile hayalinizdeki mülkü bulun.";const DEFAULT_OG_IMAGE = SITE_URL + '/static/img/og-default.jpg';function setMeta(attr,key,value){let el = document.head.querySelector(`meta[${attr}="${key}"]`);if(!el){el = document.createElement('meta');el.setAttribute(attr,key);document.head.appendChild(el);}el.setAttribute('content',value);}function setLink(rel,href){let el = document.head.querySelector(`link[rel="${rel}"]`);if(!el){el = document.createElement('link');el.setAttribute('rel',rel);document.head.appendChild(el);}el.setAttribute('href',href);}function setTitle(t){document.title = t;}function setJsonLd(data){let el = document.getElementById('structured-data-ld');if(!el){el = document.createElement('script');el.type = 'application/ld+json';el.id = 'structured-data-ld';document.head.appendChild(el);}el.textContent = JSON.stringify(data);}function setJsonLdGraph(items){setJsonLd({"@context":"https://schema.org","@graph":items});}function orgSchema(){return{"@type":"RealEstateAgent","name":SITE_NAME,"url":SITE_URL,"logo":SITE_URL + '/static/img/logo.png',"image":DEFAULT_OG_IMAGE,"telephone":"+905429663636","address":{"@type":"PostalAddress","addressLocality":"Fethiye","addressRegion":"Muğla","addressCountry":"TR"},"areaServed":["Fethiye","Muğla"],"sameAs":[]};}function websiteSchema(){return{"@type":"WebSite","name":SITE_NAME,"url":SITE_URL,"inLanguage":"tr-TR"};}function breadcrumbSchema(items){const list = items.map((it,i)=>({"@type":"ListItem","position":i + 1,"name":it.name,"item":it.url}));return{"@type":"BreadcrumbList","itemListElement":list};}function residenceSchema(portfoy){return{"@type":"Residence","name":portfoy.baslik,"url":SITE_URL + '/#detay/' + portfoy.id,"image":(portfoy.resimler && portfoy.resimler[0])?(SITE_URL + portfoy.resimler[0]):DEFAULT_OG_IMAGE,"address":{"@type":"PostalAddress","addressLocality":portfoy.ilce || "Fethiye","addressRegion":portfoy.il || "Muğla","addressCountry":"TR"},"description":portfoy.aciklama || portfoy.baslik,"category":portfoy.ana_kategori};}function updateAnasayfa(){setTitle(SITE_NAME + ' — Fethiye Gayrimenkul');setMeta('name','description',DEFAULT_DESC);setMeta('name','robots','index,follow');setLink('canonical',SITE_URL + '/');setMeta('property','og:type','website');setMeta('property','og:title',SITE_NAME + ' — Fethiye');setMeta('property','og:description',DEFAULT_DESC);setMeta('property','og:url',SITE_URL + '/');setMeta('property','og:image',DEFAULT_OG_IMAGE);setMeta('name','twitter:card','summary_large_image');setMeta('name','twitter:title',SITE_NAME);setMeta('name','twitter:description',DEFAULT_DESC);setMeta('name','twitter:image',DEFAULT_OG_IMAGE);setJsonLdGraph([{"@context":"https://schema.org",...orgSchema()},{"@context":"https://schema.org",...websiteSchema()}]);}function updateIlanlar(){const t = 'İlanlar — ' + SITE_NAME;const d = "Fethiye'de satılık ve kiralık daire,villa,arsa,iş yeri portföyleri.";setTitle(t);setMeta('name','description',d);setMeta('name','robots','index,follow');setLink('canonical',SITE_URL + '/#ilanlar');setMeta('property','og:type','website');setMeta('property','og:title',t);setMeta('property','og:description',d);setMeta('property','og:url',SITE_URL + '/#ilanlar');setMeta('property','og:image',DEFAULT_OG_IMAGE);setMeta('name','twitter:card','summary');setMeta('name','twitter:title',t);setMeta('name','twitter:description',d);setJsonLdGraph([{"@context":"https://schema.org",...orgSchema()},{"@context":"https://schema.org",...breadcrumbSchema([{name:'Ana Sayfa',url:SITE_URL + '/'},{name:'İlanlar',url:SITE_URL + '/#ilanlar'}])}]);}function updateBlog(){const t = 'Haberler — ' + SITE_NAME;const d = "Gayrimenkul piyasası,sektörel haberler ve yatırım tavsiyeleri.";setTitle(t);setMeta('name','description',d);setMeta('name','robots','index,follow');setLink('canonical',SITE_URL + '/#blog');setMeta('property','og:type','website');setMeta('property','og:title',t);setMeta('property','og:description',d);setMeta('property','og:url',SITE_URL + '/#blog');setMeta('name','twitter:card','summary');setMeta('name','twitter:title',t);setMeta('name','twitter:description',d);setJsonLdGraph([{"@context":"https://schema.org",...orgSchema()},{"@context":"https://schema.org",...breadcrumbSchema([{name:'Ana Sayfa',url:SITE_URL + '/'},{name:'Haberler',url:SITE_URL + '/#blog'}])}]);}function updateBlogDetay(blog){if(!blog)return updateBlog();const t =(blog.baslik || 'Yazı')+ ' — ' + SITE_NAME;const d = blog.ozet || blog.baslik || 'Blog yazısı';const url = SITE_URL + '/#blog-detay/' +(blog.slug || blog.id);const img = blog.kapak_resim?(SITE_URL + blog.kapak_resim):DEFAULT_OG_IMAGE;setTitle(t);setMeta('name','description',d);setMeta('name','robots','index,follow');setLink('canonical',url);setMeta('property','og:type','article');setMeta('property','og:title',t);setMeta('property','og:description',d);setMeta('property','og:url',url);setMeta('property','og:image',img);setMeta('name','twitter:card','summary_large_image');setMeta('name','twitter:title',t);setMeta('name','twitter:description',d);setMeta('name','twitter:image',img);setJsonLdGraph([{"@context":"https://schema.org",...orgSchema()},{"@context":"https://schema.org",...breadcrumbSchema([{name:'Ana Sayfa',url:SITE_URL + '/'},{name:'Haberler',url:SITE_URL + '/#blog'},{name:blog.baslik || 'Yazı',url:url}])},{"@context":"https://schema.org","@type":"Article","headline":blog.baslik,"image":img,"url":url,"description":d,"author":{"@type":"Organization","name":SITE_NAME}}]);}function updateDetay(portfoy){if(!portfoy){setTitle('Portföy Detayı — ' + SITE_NAME);setMeta('name','robots','noindex,follow');return;}const t =(portfoy.baslik || 'İlan')+ ' — ' + SITE_NAME;const d =(portfoy.aciklama || portfoy.baslik || 'Fethiye gayrimenkul').slice(0,160);const url = SITE_URL + '/#detay/' + portfoy.id;const img =(portfoy.resimler && portfoy.resimler[0])?(SITE_URL + portfoy.resimler[0]):DEFAULT_OG_IMAGE;setTitle(t);setMeta('name','description',d);setMeta('name','robots','index,follow');setLink('canonical',url);setMeta('property','og:type','website');setMeta('property','og:title',t);setMeta('property','og:description',d);setMeta('property','og:url',url);setMeta('property','og:image',img);setMeta('name','twitter:card','summary_large_image');setMeta('name','twitter:title',t);setMeta('name','twitter:description',d);setMeta('name','twitter:image',img);setJsonLdGraph([{"@context":"https://schema.org",...orgSchema()},{"@context":"https://schema.org",...breadcrumbSchema([{name:'Ana Sayfa',url:SITE_URL + '/'},{name:'İlanlar',url:SITE_URL + '/#ilanlar'},{name:portfoy.baslik || 'İlan',url:url}])},{"@context":"https://schema.org",...residenceSchema(portfoy)}]);}function updateAdmin(){setTitle('Yönetim — ' + SITE_NAME);setMeta('name','robots','noindex,nofollow');setLink('canonical',SITE_URL + '/#admin');}function updateGiris(){setTitle('Giriş — ' + SITE_NAME);setMeta('name','robots','noindex,nofollow');setLink('canonical',SITE_URL + '/#giris');}function seoUpdate(sayfa,data){try{switch(sayfa){case 'anasayfa':updateAnasayfa();break;case 'ilanlar':updateIlanlar();break;case 'blog':updateBlog();break;case 'blog-detay':updateBlogDetay(data && data.blog);break;case 'detay':updateDetay(data && data.portfoy);break;case 'admin':updateAdmin();break;case 'giris':updateGiris();break;default:updateAnasayfa();break;}}catch(e){console.warn('SEO update hatası:',e);}}global.seoUpdate = seoUpdate;global.seo ={updateAnasayfa,updateIlanlar,updateBlog,updateBlogDetay,updateDetay,updateAdmin,updateGiris};})(window);